public class TicketBookingService
{
    private readonly IDbContextFactory<BookingDbContext> _contextFactory;
    private const int MaxRetries = 3;
    private const int MaxTicketsPerPurchase = 10;

    public TicketBookingService(IDbContextFactory<BookingDbContext> contextFactory)
    {
        _contextFactory = contextFactory ?? throw new ArgumentNullException(nameof(contextFactory));
    }

    public async Task<PurchaseResult> PurchaseTicketsAsync(int eventId, string customerEmail, int quantity)
    {
        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Customer email is required."
            };
        }

        if (quantity <= 0)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = "Quantity must be greater than zero."
            };
        }

        if (quantity > MaxTicketsPerPurchase)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = $"Cannot purchase more than {MaxTicketsPerPurchase} tickets at once."
            };
        }

        int retryCount = 0;

        while (retryCount < MaxRetries)
        {
            try
            {
                using var context = await _contextFactory.CreateDbContextAsync();

                var executionStrategy = context.Database.CreateExecutionStrategy();

                return await executionStrategy.ExecuteAsync(async () =>
                {
                    using var transaction = await context.Database.BeginTransactionAsync(
                        System.Data.IsolationLevel.Serializable);

                    try
                    {
                        var eventEntity = await context.Events
                            .FirstOrDefaultAsync(e => e.EventId == eventId);

                        if (eventEntity == null)
                        {
                            return new PurchaseResult
                            {
                                Success = false,
                                Message = "Event not found."
                            };
                        }

                        if (eventEntity.AvailableSeats < quantity)
                        {
                            return new PurchaseResult
                            {
                                Success = false,
                                Message = $"Not enough seats available. Only {eventEntity.AvailableSeats} seats remaining."
                            };
                        }

                        eventEntity.AvailableSeats -= quantity;

                        var purchase = new TicketPurchase
                        {
                            EventId = eventId,
                            CustomerEmail = customerEmail,
                            Quantity = quantity,
                            PurchasedAt = DateTime.UtcNow
                        };

                        context.TicketPurchases.Add(purchase);

                        await context.SaveChangesAsync();
                        await transaction.CommitAsync();

                        return new PurchaseResult
                        {
                            Success = true,
                            Message = $"Successfully purchased {quantity} ticket(s).",
                            PurchaseId = purchase.PurchaseId
                        };
                    }
                    catch
                    {
                        await transaction.RollbackAsync();
                        throw;
                    }
                });
            }
            catch (DbUpdateConcurrencyException)
            {
                retryCount++;

                if (retryCount >= MaxRetries)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = "The system is experiencing high demand. Please try again shortly."
                    };
                }

                await Task.Delay(TimeSpan.FromMilliseconds(100 * Math.Pow(2, retryCount)));
            }
            catch (Exception ex)
            {
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"An unexpected error occurred: {ex.Message}"
                };
            }
        }

        return new PurchaseResult
        {
            Success = false,
            Message = "Failed to complete the purchase after multiple attempts."
        };
    }

    public async Task<PurchaseResult> PurchaseTicketsOptimisticAsync(int eventId, string customerEmail, int quantity)
    {
        if (string.IsNullOrWhiteSpace(customerEmail))
        {
            return new PurchaseResult { Success = false, Message = "Customer email is required." };
        }

        if (quantity <= 0 || quantity > MaxTicketsPerPurchase)
        {
            return new PurchaseResult
            {
                Success = false,
                Message = quantity <= 0
                    ? "Quantity must be greater than zero."
                    : $"Cannot purchase more than {MaxTicketsPerPurchase} tickets at once."
            };
        }

        int retryCount = 0;

        while (retryCount < MaxRetries)
        {
            try
            {
                using var context = await _contextFactory.CreateDbContextAsync();

                var eventEntity = await context.Events
                    .FirstOrDefaultAsync(e => e.EventId == eventId);

                if (eventEntity == null)
                {
                    return new PurchaseResult { Success = false, Message = "Event not found." };
                }

                if (eventEntity.AvailableSeats < quantity)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = $"Not enough seats available. Only {eventEntity.AvailableSeats} seats remaining."
                    };
                }

                eventEntity.AvailableSeats -= quantity;

                var purchase = new TicketPurchase
                {
                    EventId = eventId,
                    CustomerEmail = customerEmail,
                    Quantity = quantity,
                    PurchasedAt = DateTime.UtcNow
                };

                context.TicketPurchases.Add(purchase);

                await context.SaveChangesAsync();

                return new PurchaseResult
                {
                    Success = true,
                    Message = $"Successfully purchased {quantity} ticket(s).",
                    PurchaseId = purchase.PurchaseId
                };
            }
            catch (DbUpdateConcurrencyException ex)
            {
                retryCount++;

                if (retryCount >= MaxRetries)
                {
                    return new PurchaseResult
                    {
                        Success = false,
                        Message = "The system is experiencing high demand. Please try again shortly."
                    };
                }

                foreach (var entry in ex.Entries)
                {
                    await entry.ReloadAsync();
                }

                await Task.Delay(TimeSpan.FromMilliseconds(50 * Math.Pow(2, retryCount)));
            }
            catch (Exception ex)
            {
                return new PurchaseResult
                {
                    Success = false,
                    Message = $"An unexpected error occurred: {ex.Message}"
                };
            }
        }

        return new PurchaseResult
        {
            Success = false,
            Message = "Failed to complete the purchase after multiple attempts."
        };
    }

    public async Task<int> GetAvailableSeatsAsync(int eventId)
